export interface Delimiters {
  start: string;
  end: string;
}

export function getDelimiters(fileName: string, markerName: string): Delimiters {
  const isGitignore =
    fileName === '.gitignore' || fileName.endsWith('.gitignore');
  if (isGitignore) {
    return {
      start: `# kdoc:${markerName}:start`,
      end: `# kdoc:${markerName}:end`,
    };
  }
  return {
    start: `<!-- kdoc:${markerName}:start -->`,
    end: `<!-- kdoc:${markerName}:end -->`,
  };
}

export function injectMarkerBlock(
  fileContent: string,
  blockContent: string,
  fileName: string,
  markerName: string,
): string {
  const { start, end } = getDelimiters(fileName, markerName);
  const fullBlock = `${start}\n${blockContent}\n${end}`;

  const hasStart = fileContent.includes(start);
  const hasEnd = fileContent.includes(end);

  if (hasStart !== hasEnd) {
    throw new Error(
      `Corrupted kdoc markers in ${fileName}: found ${hasStart ? 'start' : 'end'} marker for "${markerName}" but not the other. ` +
      `Fix manually by adding the missing marker or removing the orphaned one.`,
    );
  }

  if (hasStart && hasEnd) {
    const startIdx = fileContent.indexOf(start);
    const endIdx = fileContent.indexOf(end) + end.length;
    return fileContent.slice(0, startIdx) + fullBlock + fileContent.slice(endIdx);
  }

  if (fileContent.length === 0) return fullBlock;

  const separator = fileContent.endsWith('\n') ? '\n' : '\n\n';
  return fileContent + separator + fullBlock;
}

export function removeMarkerBlock(
  fileContent: string,
  fileName: string,
  markerName: string,
): string {
  const { start, end } = getDelimiters(fileName, markerName);

  const hasStart = fileContent.includes(start);
  const hasEnd = fileContent.includes(end);

  if (hasStart !== hasEnd) {
    throw new Error(
      `Corrupted kdoc markers in ${fileName}: found ${hasStart ? 'start' : 'end'} marker for "${markerName}" but not the other. ` +
      `Fix manually by adding the missing marker or removing the orphaned one.`,
    );
  }

  if (!hasStart && !hasEnd) {
    return fileContent;
  }

  const startIdx = fileContent.indexOf(start);
  const endIdx = fileContent.indexOf(end) + end.length;
  const before = fileContent.slice(0, startIdx);
  const after = fileContent.slice(endIdx);

  return (before + after).replace(/\n{3,}/g, '\n\n').trim();
}

export function extractMarkerBlock(
  fileContent: string,
  fileName: string,
  markerName: string,
): string | null {
  const { start, end } = getDelimiters(fileName, markerName);

  if (!fileContent.includes(start) || !fileContent.includes(end)) return null;

  const startIdx = fileContent.indexOf(start) + start.length;
  const endIdx = fileContent.indexOf(end);

  return fileContent.slice(startIdx, endIdx).trim();
}
